Connect this project to ap.consciousness.london for cross-session telemetry and APGPS.

## Usage

```
/apgps                # connect (opens browser if needed, skips if already authed)
/apgps status         # show connection status, CE score, and session metrics
/apgps disconnect     # disconnect THIS project (keeps other projects connected)
/apgps disconnect all # sign out of every project on this dashboard
```

## Instructions

All subcommands share the same CLI resolution. Run this block first to locate
the config-manager CLI, then branch on the argument:

```bash
# Resolve config-manager CLI — prefer CLAUDE_PLUGIN_ROOT, fall back to marketplace cache
if [ -n "${CLAUDE_PLUGIN_ROOT:-}" ] && [ -f "/home/powell-clark/projects/amalavijnana/consciousness/adapters/claude-code/dist/packages/core/setup-wizard/config-manager/cli.js" ]; then
  APGPS_CLI="/home/powell-clark/projects/amalavijnana/consciousness/adapters/claude-code/dist/packages/core/setup-wizard/config-manager/cli.js"
else
  APGPS_CLI=$(ls ~/.claude/plugins/cache/powell-clark/consciousness/*/dist/packages/core/setup-wizard/config-manager/cli.js 2>/dev/null | sort -V | tail -1)
fi
if [ -z "$APGPS_CLI" ]; then
  echo "ERROR: config-manager CLI not found. Set CLAUDE_PLUGIN_ROOT or re-install the consciousness plugin."
  exit 1
fi
```

### No arguments — connect

```bash
node "$APGPS_CLI" --auth
```

If valid credentials already exist in `~/.consciousness/credentials.json`, this enables sync for the current project without opening a browser. Only opens the browser when no credentials are found or they're expired.

### `status`

Run auth status, then the health dashboard:

```bash
node "$APGPS_CLI" --auth-status
```

Then run:

```bash
node << 'APGPS_STATUS_EOF'
const fs = require('fs');
const path = require('path');

const root = process.cwd();
const cDir = path.join(root, 'CONSCIOUSNESS');
const streamDir = path.join(cDir, 'stream');
const configPath = path.join(cDir, 'config.json');
const sessionsPath = fs.existsSync(path.join(streamDir, 'sessions-history.json'))
  ? path.join(streamDir, 'sessions-history.json')
  : path.join(cDir, 'sessions.json');
const activePath = fs.existsSync(path.join(streamDir, 'active-sessions.json'))
  ? path.join(streamDir, 'active-sessions.json')
  : path.join(cDir, 'active-sessions.json');

const IS_ADMIN = fs.existsSync(path.join(cDir, 'directives'))
  && fs.existsSync(path.join(root, '.claude-plugin', 'plugin.json'));

function readJson(file, fallback) {
  try { return JSON.parse(fs.readFileSync(file, 'utf-8')); } catch { return fallback; }
}

function durationMinutes(session) {
  if (!session.started) return 0;
  const start = new Date(String(session.started).endsWith('Z') ? session.started : String(session.started).replace(/\s+\w.*$/, '') + 'Z');
  const end = session.ended ? new Date(String(session.ended).endsWith('Z') ? session.ended : String(session.ended).replace(/\s+\w.*$/, '') + 'Z') : new Date();
  const value = (end.getTime() - start.getTime()) / 60000;
  return Number.isFinite(value) ? Math.max(0, value) : 0;
}

const config = readJson(configPath, {});
const sessions = readJson(sessionsPath, { sessions: [] }).sessions || [];
const activeRaw = readJson(activePath, { sessions: {} }).sessions || {};
const activeCount = Array.isArray(activeRaw) ? activeRaw.length : Object.keys(activeRaw).length;
const today = new Date().toISOString().slice(0, 10);
const todaySessions = sessions.filter(s => String(s.started || '').startsWith(today));

let totalMin = 0, totalTasks = 0, totalErrors = 0, totalTurns = 0, totalCommits = 0;
for (const s of todaySessions) {
  const m = s.metrics || {};
  totalMin += durationMinutes(s);
  totalTasks += Array.isArray(m.tasks_completed) ? m.tasks_completed.length : 0;
  totalErrors += Number.isFinite(Number(m.errors)) ? Number(m.errors) : 0;
  totalTurns += Number.isFinite(Number(m.turns)) ? Number(m.turns) : 0;
  totalCommits += Number.isFinite(Number(m.commits)) ? Number(m.commits) : 0;
}

const retentionOk = fs.existsSync(path.join(cDir, 'tasks', 'TASK-ACTIVE-INDEX.md'))
  || fs.existsSync(path.join(cDir, 'tasks', 'active-task-item-details'));
const availability = Math.min(1, totalMin / 1440);
const expectedTasks = Math.max(1, totalMin / 30);
const performance = Math.min(1, totalTasks / expectedTasks);
const quality = totalTurns > 0 ? Math.max(0, 1 - totalErrors / totalTurns) : 1;
const retention = retentionOk ? 1 : 0;
const ce = retention ? availability * performance * quality * retention : 0;
const sync = config.sync || {};
const telemetry = config.telemetry || {};

console.log();
console.log('='.repeat(64));
console.log(IS_ADMIN ? '  HEALTH (ADMIN)' : '  HEALTH');
console.log('='.repeat(64));
console.log();
console.log('  CE: CONSCIOUSNESS EFFECTIVENESS');
console.log('-'.repeat(64));
if (retentionOk) {
  const bar = v => { const n = Number.isFinite(v) ? Math.max(0, Math.min(1, v)) : 0; const f = Math.round(n * 40); return '█'.repeat(f) + '░'.repeat(40 - f); };
  console.log(`  [${bar(ce)}] ${(ce * 100).toFixed(0)}%`);
  console.log(`  Availability: ${(availability * 100).toFixed(0).padStart(4)}%  ${totalMin.toFixed(0)}/1440 min`);
  console.log(`  Performance:  ${(performance * 100).toFixed(0).padStart(4)}%  ${totalTasks}/${expectedTasks.toFixed(1)} tasks`);
  console.log(`  Quality:      ${(quality * 100).toFixed(0).padStart(4)}%  ${totalErrors} errors / ${totalTurns} turns`);
  console.log(`  Retention:     100%  PGPS intact`);
} else {
  console.log('  CE skipped — PGPS missing');
}
console.log();
console.log("  TODAY'S SESSIONS");
console.log('-'.repeat(64));
console.log(`  Sessions: ${todaySessions.length}  |  Active: ${activeCount}  |  Turns: ${totalTurns}  |  Commits: ${totalCommits}  |  Errors: ${totalErrors}`);
console.log();
console.log('  SYNC');
console.log('-'.repeat(64));
console.log(`  Sync: ${sync.enabled ? 'enabled' : 'disabled'}`);
if (sync.enabled) {
  const hasKey = !!process.env[sync.api_key_env || ''];
  console.log(`  Endpoint: ${sync.endpoint || '(not set)'}`);
  console.log(`  API Key:  ${hasKey ? 'set' : 'MISSING (' + (sync.api_key_env || '?') + ')'}`);
}
console.log(`  Telemetry opt-in: ${telemetry.enabled === true ? 'enabled' : 'disabled'}`);

if (IS_ADMIN) {
  const DOMAINS = [
    'consciousness.sh', 'consciousness.london', 'ishiki.london',
    'chetna.london', 'conciencia.london', 'conscience.london',
    'bewusstsein.london', 'aiji.london', 'waiy.london', 'agahi.london',
    'jisik.london', 'todaa.london', 'uisik.london', 'yishi.london',
    'ythuc.london', 'bilinc.london', 'mwamko.london', 'shaoor.london',
    'unarvu.london', 'anidaho.london', 'chetona.london', 'soznanie.london',
    'coscienza.london', 'kamalayan.london', 'kesadaran.london',
    'svidomist.london', 'bewustzijn.london', 'jitsamneuk.london',
    'swiadomosc.london', 'consciencia.london', 'conscientia.london',
  ];
  console.log();
  console.log('  DOMAIN HEALTH');
  console.log('-'.repeat(64));
  try {
    const { execFileSync } = require('child_process');
    const args = ['--parallel', '--parallel-max', '15'];
    for (const d of DOMAINS) {
      args.push('-s', '-L', '-o', '/dev/null', '-w', d + ' %{http_code}\n',
        '--connect-timeout', '3', '--max-time', '5', 'https://' + d + '/');
    }
    const raw = execFileSync('curl', args, { timeout: 30000, encoding: 'utf-8', stdio: ['pipe', 'pipe', 'pipe'] }).trim();
    const results = raw.split('\n').filter(Boolean).map(l => {
      const p = l.trim().split(/\s+/);
      return { domain: p[0], code: p[1] || '000' };
    });
    const ok = results.filter(r => r.code === '401');
    const bad = results.filter(r => r.code !== '401' && !r.code.startsWith('000'));
    const down = results.filter(r => r.code.startsWith('000'));
    console.log(`  Checked: ${results.length}/${DOMAINS.length}  |  Protected: ${ok.length}  |  Down: ${down.length}`);
    if (bad.length > 0) {
      console.log(`  BREACH: ${bad.length} serving without auth`);
      for (const r of bad) console.log(`    ${r.domain} -> ${r.code}`);
    } else {
      console.log('  Status: all protected');
    }
  } catch (e) { console.log(`  Error: ${e.message}`); }
}

console.log();
console.log('='.repeat(64));
console.log(`  ${new Date().toISOString().replace('T', ' ').slice(0, 19)}`);
console.log('='.repeat(64));
APGPS_STATUS_EOF
```

Display both outputs exactly as-is. Do NOT add commentary.

### `disconnect`

Disconnect **this project only** (the default — keeps the shared credential so other projects keep syncing, issue #520):

```bash
node "$APGPS_CLI" --auth-revoke
```

This sets `sync.enabled: false` in the current project's CONSCIOUSNESS/config.json and **keeps** `~/.consciousness/credentials.json`.

**Only** when the user explicitly asks to sign out of *every* project (e.g. `/apgps disconnect all`) — and never as part of the default disconnect — run instead:

```bash
node "$APGPS_CLI" --auth-revoke --all
```

That additionally clears `~/.consciousness/credentials.json` — every project on this dashboard is signed out (credentials are endpoint-scoped, shared across projects). Do NOT run both commands; pick exactly one based on whether the user asked for "all".

## Notes

